using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut;

    public OrderServiceTests()
    {
        _sut = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    // --- CreateOrder ---

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 2), ("Gadget", 25.00m, 1));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(45.00m, order.Total); // 10*2 + 25*1
        Assert.AreSame(items, order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_AssignsNonEmptyId()
    {
        var items = CreateItems(("Widget", 5.00m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 5.00m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}.");
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_CalculatesTotalCorrectly()
    {
        var items = CreateItems(("Widget", 7.50m, 4));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(30.00m, order.Total); // 7.50 * 4
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(1)]
    [DataRow(100)]
    public void CreateOrder_WithVariousQuantities_CalculatesTotalCorrectly(int quantity)
    {
        var items = CreateItems(("Widget", 10.00m, quantity));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(10.00m * quantity, order.Total);
    }

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 5.00m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));
        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_AssignsUniqueIds()
    {
        var items = CreateItems(("Widget", 1.00m, 1));

        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingOrderId_ReturnsMatchingOrder()
    {
        var items = CreateItems(("Widget", 5.00m, 1));
        var created = _sut.CreateOrder("cust-1", items);

        var retrieved = _sut.GetOrder(created.Id);

        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithOrders_ReturnsAllMatchingOrders()
    {
        var items = CreateItems(("Widget", 5.00m, 1));
        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);
        _sut.CreateOrder("cust-2", items); // different customer

        var result = _sut.GetOrdersByCustomer("cust-1");

        Assert.HasCount(2, result);
        Assert.Contains(order1, result);
        Assert.Contains(order2, result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithNoOrders_ReturnsEmptyList()
    {
        var result = _sut.GetOrdersByCustomer("no-orders");

        Assert.IsEmpty(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_DoesNotReturnOtherCustomerOrders()
    {
        var items = CreateItems(("Widget", 5.00m, 1));
        var otherOrder = _sut.CreateOrder("cust-2", items);

        var result = _sut.GetOrdersByCustomer("cust-1");

        Assert.DoesNotContain(otherOrder, result);
    }
}

